@namespace Lumeo

<nav aria-label="breadcrumb" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</nav>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"{Class}".Trim();
}

@namespace Lumeo

<li role="presentation" class="@CssClass" @attributes="AdditionalAttributes">
    <Blazicon Svg="Lucide.Ellipsis" class="h-4 w-4" />
    <span class="sr-only">More</span>
</li>

@code {
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"flex items-center justify-center {Class}".Trim();
}

@namespace Lumeo

<li class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</li>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"inline-flex items-center gap-1.5 {Class}".Trim();
}

@namespace Lumeo

<a href="@Href" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</a>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Href { get; set; } = "#";
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"cursor-pointer transition-colors hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-sm {Class}".Trim();
}

@namespace Lumeo

<ol class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</ol>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"flex flex-wrap items-center gap-1.5 break-words text-sm text-muted-foreground sm:gap-2.5 {Class}".Trim();
}

@namespace Lumeo

<span role="link" aria-disabled="true" aria-current="page" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</span>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"font-normal text-foreground {Class}".Trim();
}

@namespace Lumeo

<li role="presentation" aria-hidden="true" class="@CssClass" @attributes="AdditionalAttributes">
    @if (ChildContent is not null)
    {
        @ChildContent
    }
    else
    {
        <Blazicon Svg="Lucide.ChevronRight" class="h-3.5 w-3.5" />
    }
</li>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"[&>svg]:h-3.5 [&>svg]:w-3.5 {Class}".Trim();
}
